3	const readStdin = (): Promise<string> =>
4	  new Promise((resolve) => {
5	    let data = "";
6	    process.stdin.setEncoding("utf-8");
7	    process.stdin.on("data", (chunk) => { data += chunk; });
8	    process.stdin.on("end", () => resolve(data));
9	  });
10	
11	const main = async () => {
12	  try {
13	    const input = await readStdin();
14	    const scenario = JSON.parse(input) as Scenario;
15	    const result = runScenario(scenario);
16	    process.stdout.write(JSON.stringify(result));
17	  } catch (err) {
18	    process.stderr.write(err instanceof Error ? err.message : String(err));
19	    process.exit(1);
20	  }
21	};
22	
23	main();
